    /// [multi-gpu ①] Prove only THIS worker's shard of continuation segments (one GPU/process).
    ProveSegments,
    /// [multi-gpu ①] Aggregate serialized segment proofs (from all workers) into the final STARK.
    Aggregate,
RS
run edit_replace "$RBLIB" "$TMP/e6c_old.txt" "$TMP/e6c_new.txt" "ProveSegments,"
printf '%s' '            Self::ProveStark => write!(f, "prove_stark"),' > "$TMP/e6d_old.txt"
cat > "$TMP/e6d_new.txt" <<'RS'
            Self::ProveStark => write!(f, "prove_stark"),
            Self::ProveSegments => write!(f, "prove_segments"),
            Self::Aggregate => write!(f, "aggregate"),
RS
run edit_replace "$RBLIB" "$TMP/e6d_old.txt" "$TMP/e6d_new.txt" 'f, "prove_segments"'
printf '%s' '    pub num_gpus: usize,' > "$TMP/e6e_old.txt"
cat > "$TMP/e6e_new.txt" <<'RS'
    pub num_gpus: usize,

    /// [multi-gpu ①] this worker's id in 0..num_workers (mode=prove-segments).
    #[arg(long, default_value_t = 0)]
    pub worker_id: usize,
    /// [multi-gpu ①] total workers = GPUs (mode=prove-segments / aggregate).
    #[arg(long, default_value_t = 1)]
    pub num_workers: usize,
    /// [multi-gpu ①] dir for serialized segment proofs (prove-segments writes, aggregate reads).
    #[arg(long)]
    pub segments_out: Option<PathBuf>,
RS
run edit_replace "$RBLIB" "$TMP/e6e_old.txt" "$TMP/e6e_new.txt" "pub worker_id: usize"
printf '%s' '                    BenchMode::GenerateFixtures => {' > "$TMP/e6f_old.txt"
cat > "$TMP/e6f_new.txt" <<'RS'
