RS
# marker must be UNIQUE to the ARM (not the enum doc-comment that Edit 6c added, which also contains
# "Prove only THIS worker") — else 6f SKIPs and the match arm is never inserted -> runtime unreachable!().
run edit_replace "$RBLIB" "$TMP/e6f_old.txt" "$TMP/e6f_new.txt" 'required for prove-segments'

# ── workspace exclude: stop cargo from claiming .vendor/* as openvm-eth members ─
# Without this, the vendored crates' `authors.workspace = true` (and other inherited
# fields) resolve against openvm-eth's [workspace.package] (which lacks them) -> error.
echo "== workspace exclude .vendor =="
printf '%s' 'exclude = []' > "$TMP/wex_old.txt"
printf '%s' 'exclude = [".vendor"]' > "$TMP/wex_new.txt"
run edit_replace "$ETH/Cargo.toml" "$TMP/wex_old.txt" "$TMP/wex_new.txt" 'exclude = [".vendor"]'

# ── cargo [patch] — auto-discovered from Cargo.lock + vendored crate dirs ─────
echo "== cargo [patch] overrides =="
if grep -q 'BEGIN openvm-infra multi-gpu patch' "$ETH/Cargo.toml" 2>/dev/null; then
  echo "  SKIP (patch section already present)"
else
  py "$LOCK" "$VENDOR" >> "$TMP/patch.toml" <<'PY'
import sys, re, os, subprocess
lock, vendor = sys.argv[1], sys.argv[2]
txt = open(lock, encoding='utf-8').read()
# package blocks: name + source
blocks = re.findall(r'\[\[package\]\]\nname = "([^"]+)"\nversion = "[^"]+"\nsource = "([^"]+)"', txt)
def crate_dir(repo_root, name):
    # find the crate dir whose Cargo.toml declares `name = "<name>"`
    try:
        out = subprocess.run(["grep","-rlE",f'^name = "{re.escape(name)}"',"--include=Cargo.toml",repo_root],
                             capture_output=True, text=True).stdout.strip().splitlines()
    except Exception:
        out = []
    return os.path.dirname(out[0]) if out else None
sources = {
  "https://github.com/openvm-org/openvm.git":        (f"{vendor}/openvm",        []),
  "https://github.com/openvm-org/stark-backend.git": (f"{vendor}/stark-backend", []),
}
seen=set()
for name, src in blocks:
    for url,(root,acc) in sources.items():
        if url in src and name not in seen:
            seen.add(name)
            d = crate_dir(root, name)
            if d: acc.append((name, os.path.relpath(d, os.path.dirname(lock))))
            else: print(f"# WARN: crate dir for {name} not found under {root}", file=sys.stderr)
print("# BEGIN openvm-infra multi-gpu patch (auto-generated)")
for url,(root,acc) in sources.items():
    if not acc: continue
    print(f'[patch."{url}"]')
    for name,rel in sorted(acc):
        print(f'{name} = {{ path = "{rel}" }}')
print("# END openvm-infra multi-gpu patch")
PY
  if [[ -s "$TMP/patch.toml" ]]; then
    printf '\n' >> "$ETH/Cargo.toml"; cat "$TMP/patch.toml" >> "$ETH/Cargo.toml"
    echo "  OK: appended [patch] for $(grep -c '= { path' "$TMP/patch.toml") crates"
  else
    echo "  FAIL: produced no [patch] entries (inspect Cargo.lock format)"; FAILED=1
  fi
fi

# ── keep the committed Cargo.lock (minimal-churn build) ──────────────────────
# CRITICAL: a full re-resolve ("Locking … to latest compatible") bumps transitive deps
# like winnow 0.7 -> 1.0, which breaks alloy-dyn-abi 1.5.x (142 errors). Restoring the
# committed lock means the first `cargo build` only ADDS the vendored crates (same versions
# openvm-eth already pinned) and keeps everything else put.
if git -C "$ETH" rev-parse --git-dir >/dev/null 2>&1; then
  git -C "$ETH" checkout -- Cargo.lock 2>/dev/null && echo "restored committed Cargo.lock (avoids winnow/alloy re-resolve)"
fi

echo ""
echo "== summary =="
echo "vendored: $VENDOR/openvm @ $OPENVM_REV ; $VENDOR/stark-backend @ $STARK_REV"
if [[ "$FAILED" == 0 ]]; then
  echo "ALL EDITS APPLIED. Next (FREE, no GPU): cd $ETH && cargo build --release --bin openvm-reth-benchmark"
  echo "Then on the box: cargo build --release --bin openvm-reth-benchmark --features cuda"
else
  echo ">>> SOME EDITS FAILED (rev drift). Hand-apply the FAILed ones from ../docs/openvm-multigpu.md, then re-run."
  exit 1
fi
